def _validar_fondo() -> None:
    """Mismo espíritu que el validador de pixelart.py: un pixel fuera de
    paleta explota acá, con número de fila, no como una mancha rara en
    pantalla."""
    validos = set(PALETA)
    if len(FONDO) != ALTO_FONDO or {len(f) for f in FONDO} != {ANCHO_FONDO}:
        raise ValueError(f"el fondo no mide {ANCHO_FONDO}x{ALTO_FONDO}")
    for numero, fila in enumerate(FONDO):
        if intrusos := set(fila) - validos:
            raise ValueError(f"fondo, fila {numero}: chars {intrusos!r}")


_validar_fondo()


def exportar_fondo() -> dict:
    """El paquete que viaja por ``GET /api/fondo``: paleta + grilla, tal
    cual (se manda la paleta de nuevo, aunque /api/retratos también la
    tenga, para que este endpoint no dependa de pedidos previos)."""
    return {
        "paleta": PALETA,
        "ancho": ANCHO_FONDO,
        "alto": ALTO_FONDO,
        "filas": FONDO,
    }
